terraform:
terraform {
  required_version = ">= 1.5"
}

locals {
  tags = {
    project     = "archmorph"
    environment = "dev"
    managed_by  = "archmorph"
  }
}

resource "azurerm_user_assigned_identity" "app" {
  name                = "id-aws-web-secure"
  location            = "westeurope"
  resource_group_name = "rg-aws-web-secure"
  tags                = local.tags
}

resource "azurerm_key_vault" "main" {
  name                        = "kvawswebsecure01"
  location                    = "westeurope"
  resource_group_name         = "rg-aws-web-secure"
  tenant_id                   = "00000000-0000-0000-0000-000000000000"
  sku_name                    = "standard"
  purge_protection_enabled    = true
  soft_delete_retention_days  = 7
  enable_rbac_authorization   = true
  public_network_access_enabled = false
  tags                        = local.tags
}

resource "azurerm_storage_account" "main" {
  name                            = "stawswebsecure01"
  location                        = "westeurope"
  resource_group_name             = "rg-aws-web-secure"
  account_tier                    = "Standard"
  account_replication_type        = "LRS"
  min_tls_version                 = "TLS1_2"
  public_network_access_enabled   = false
  infrastructure_encryption_enabled = true
  identity {
    type = "SystemAssigned"
  }
  tags = local.tags
}

resource "azurerm_private_endpoint" "storage" {
  name                = "pe-aws-web-storage"
  location            = "westeurope"
  resource_group_name = "rg-aws-web-secure"
  subnet_id           = "/subscriptions/000/resourceGroups/rg/providers/Microsoft.Network/virtualNetworks/vnet/subnets/private"

  private_service_connection {
    name                           = "psc-storage"
    private_connection_resource_id = azurerm_storage_account.main.id
    subresource_names              = ["blob"]
    is_manual_connection           = false
  }
}

resource "azurerm_log_analytics_workspace" "main" {
  name                = "law-aws-web-secure"
  location            = "westeurope"
  resource_group_name = "rg-aws-web-secure"
  sku                 = "PerGB2018"
  retention_in_days   = 30
  tags                = local.tags
}

resource "azurerm_monitor_diagnostic_setting" "storage" {
  name                       = "diag-storage"
  target_resource_id         = azurerm_storage_account.main.id
  log_analytics_workspace_id = azurerm_log_analytics_workspace.main.id

  enabled_log {
    category = "StorageRead"
  }

  metric {
    category = "AllMetrics"
    enabled  = true
  }
}

resource "azurerm_web_application_firewall_policy" "main" {
  name                = "waf-aws-web-secure"
  resource_group_name = "rg-aws-web-secure"
  location            = "westeurope"

  policy_settings {
    enabled = true
    mode    = "Prevention"
  }

  managed_rules {
    managed_rule_set {
      type    = "OWASP"
      version = "3.2"
    }
  }

  tags = local.tags
}

bicep:
targetScope = 'subscription'

param location string = 'westeurope'

var tags = {
  project: 'archmorph'
  environment: 'dev'
  managedBy: 'archmorph'
}

resource identity 'Microsoft.ManagedIdentity/userAssignedIdentities@2023-01-31' = {
  name: 'id-aws-web-secure'
  location: location
  tags: tags
}

resource keyVault 'Microsoft.KeyVault/vaults@2023-07-01' = {
  name: 'kv-aws-web-secure'
  location: location
  properties: {
    tenantId: '00000000-0000-0000-0000-000000000000'
    sku: {
      family: 'A'
      name: 'standard'
    }
    enableRbacAuthorization: true
    publicNetworkAccess: 'Disabled'
  }
  tags: tags
}

resource storage 'Microsoft.Storage/storageAccounts@2023-05-01' = {
  name: 'stawswebsecure01'
  location: location
  sku: {
    name: 'Standard_LRS'
  }
  kind: 'StorageV2'
  identity: {
    type: 'SystemAssigned'
  }
  properties: {
    minimumTlsVersion: '1.2'
    publicNetworkAccess: 'Disabled'
  }
  tags: tags
}

resource privateEndpoint 'Microsoft.Network/privateEndpoints@2023-09-01' = {
  name: 'pe-aws-web-storage'
  location: location
  properties: {
    subnet: {
      id: '/subscriptions/000/resourceGroups/rg/providers/Microsoft.Network/virtualNetworks/vnet/subnets/private'
    }
    privateLinkServiceConnections: [
      {
        name: 'storage-link'
        properties: {
          privateLinkServiceId: storage.id
          groupIds: [
            'blob'
          ]
        }
      }
    ]
  }
  tags: tags
}

resource workspace 'Microsoft.OperationalInsights/workspaces@2023-09-01' = {
  name: 'law-aws-web-secure'
  location: location
  properties: {
    sku: {
      name: 'PerGB2018'
    }
  }
  tags: tags
}

resource storageDiag 'Microsoft.Insights/diagnosticSettings@2021-05-01-preview' = {
  name: 'diag-storage'
  scope: storage
  properties: {
    workspaceId: workspace.id
    logs: [
      {
        category: 'StorageRead'
        enabled: true
      }
    ]
    metrics: [
      {
        category: 'AllMetrics'
        enabled: true
      }
    ]
  }
}

resource wafPolicy 'Microsoft.Network/applicationGatewayWebApplicationFirewallPolicies@2023-09-01' = {
  name: 'waf-aws-web-secure'
  location: location
  properties: {
    policySettings: {
      enabledState: 'Enabled'
      mode: 'Prevention'
    }
    managedRules: {
      managedRuleSets: [
        {
          ruleSetType: 'OWASP'
          ruleSetVersion: '3.2'
        }
      ]
    }
  }
  tags: tags
}
